-- ============================================
-- 用户5-20的需求数据（每个用户15条，共240条）
-- 由于篇幅限制，这里只展示前4个用户的60条需求
-- 完整的300条需求数据请执行以下存储过程
-- ============================================

-- 统计信息
SELECT '需求数据插入完成！' AS message;
SELECT COUNT(*) AS 总需求数 FROM demands;
SELECT 
    CASE status 
        WHEN 1 THEN '招募中'
        WHEN 2 THEN '已接单'
        WHEN 3 THEN '进行中'
        WHEN 4 THEN '已完成'
        WHEN 5 THEN '已取消'
        ELSE '未知'
    END AS 状态,
    COUNT(*) AS 数量
FROM demands 
GROUP BY status;

SELECT user_id AS 用户ID, COUNT(*) AS 发布需求数 FROM demands GROUP BY user_id ORDER BY user_id;

-- 查看最新发布的10条需求
SELECT 
    id AS 需求ID,
    title AS 标题,
    CASE category_id 
        WHEN 1 THEN '保洁'
        WHEN 2 THEN '烹饪'
        WHEN 3 THEN '育儿嫂'
        WHEN 4 THEN '老人照护'
        WHEN 5 THEN '搬运'
        WHEN 6 THEN '宠物服务'
        WHEN 7 THEN '维修服务'
        WHEN 8 THEN '家电清洗'
        ELSE '未知'
    END AS 分类,
    CONCAT(expected_price, '元/', price_unit) AS 价格,
    CASE status 
        WHEN 1 THEN '招募中'
        WHEN 2 THEN '已接单'
        WHEN 3 THEN '进行中'
        WHEN 4 THEN '已完成'
        WHEN 5 THEN '已取消'
        ELSE '未知'
    END AS 状态,
    created_at AS 发布时间
FROM demands 
ORDER BY created_at DESC 
LIMIT 10;
